17	export const createJsonErrorResponseHandler =
18	  <T>({
19	    errorSchema,
20	    errorToMessage,
21	    isRetryable,
22	  }: {
23	    errorSchema: FlexibleSchema<T>;
24	    errorToMessage: (error: T) => string;
25	    isRetryable?: (response: Response, error?: T) => boolean;
26	  }): ResponseHandler<APICallError> =>
27	  async ({ response, url, requestBodyValues }) => {
28	    const responseBody = await response.text();
29	    const responseHeaders = extractResponseHeaders(response);
30	
31	    // Some providers return an empty response body for some errors:
32	    if (responseBody.trim() === '') {
33	      return {
34	        responseHeaders,
35	        value: new APICallError({
36	          message: response.statusText,
37	          url,
38	          requestBodyValues,
39	          statusCode: response.status,
40	          responseHeaders,
41	          responseBody,
42	          isRetryable: isRetryable?.(response),
43	        }),
44	      };
45	    }
46	
47	    // resilient parsing in case the response is not JSON or does not match the schema:
48	    try {
49	      const parsedError = await parseJSON({
50	        text: responseBody,
51	        schema: errorSchema,
52	      });
53	
54	      return {
55	        responseHeaders,
56	        value: new APICallError({
57	          message: errorToMessage(parsedError),
58	          url,
59	          requestBodyValues,
60	          statusCode: response.status,
61	          responseHeaders,
62	          responseBody,
63	          data: parsedError,
64	          isRetryable: isRetryable?.(response, parsedError),
65	        }),
66	      };
67	    } catch (parseError) {
68	      return {
69	        responseHeaders,
70	        value: new APICallError({
71	          message: response.statusText,
72	          url,
73	          requestBodyValues,
74	          statusCode: response.status,
75	          responseHeaders,
76	          responseBody,
77	          isRetryable: isRetryable?.(response),
78	        }),
79	      };
80	    }
81	  };
82	
83	export const createEventSourceResponseHandler =
84	  <T>(
85	    chunkSchema: FlexibleSchema<T>,
86	  ): ResponseHandler<ReadableStream<ParseResult<T>>> =>
87	  async ({ response }: { response: Response }) => {
88	    const responseHeaders = extractResponseHeaders(response);
89	
90	    if (response.body == null) {
91	      throw new EmptyResponseBodyError({});
92	    }
93	
94	    return {
95	      responseHeaders,
96	      value: parseJsonEventStream({
97	        stream: response.body,
98	        schema: chunkSchema,
99	      }),
100	    };
101	  };
102	
103	export const createJsonResponseHandler =
104	  <T>(responseSchema: FlexibleSchema<T>): ResponseHandler<T> =>
105	  async ({ response, url, requestBodyValues }) => {
106	    const responseBody = await response.text();
107	
108	    const parsedResult = await safeParseJSON({
109	      text: responseBody,
110	      schema: responseSchema,
111	    });
112	
113	    const responseHeaders = extractResponseHeaders(response);
114	
115	    if (!parsedResult.success) {
116	      throw new APICallError({
117	        message: 'Invalid JSON response',
118	        cause: parsedResult.error,
119	        statusCode: response.status,
120	        responseHeaders,
121	        responseBody,
122	        url,
123	        requestBodyValues,
124	      });
125	    }
126	
127	    return {
128	      responseHeaders,
129	      value: parsedResult.value,
130	      rawValue: parsedResult.rawValue,
131	    };
132	  };
133	
134	export const createBinaryResponseHandler =
135	  (): ResponseHandler<Uint8Array> =>
136	  async ({ response, url, requestBodyValues }) => {
137	    const responseHeaders = extractResponseHeaders(response);
138	
139	    if (!response.body) {
140	      throw new APICallError({
141	        message: 'Response body is empty',
142	        url,
143	        requestBodyValues,
144	        statusCode: response.status,
145	        responseHeaders,
146	        responseBody: undefined,
147	      });
148	    }
149	
150	    try {
151	      const buffer = await response.arrayBuffer();
152	      return {
153	        responseHeaders,
154	        value: new Uint8Array(buffer),
155	      };
156	    } catch (error) {
157	      throw new APICallError({
158	        message: 'Failed to read response as array buffer',
159	        url,
160	        requestBodyValues,
161	        statusCode: response.status,
162	        responseHeaders,
163	        responseBody: undefined,
164	        cause: error,
165	      });
166	    }
167	  };
168	
169	export const createStatusCodeErrorResponseHandler =
170	  (): ResponseHandler<APICallError> =>
171	  async ({ response, url, requestBodyValues }) => {
172	    const responseHeaders = extractResponseHeaders(response);
173	    const responseBody = await response.text();
174	
175	    return {
176	      responseHeaders,
177	      value: new APICallError({
178	        message: response.statusText,
179	        url,
180	        requestBodyValues: requestBodyValues as Record<string, unknown>,
181	        statusCode: response.status,
182	        responseHeaders,
183	        responseBody,
184	      }),
185	    };
186	  };
