export interface ProdiaProviderSettings {
  apiKey?: string;  // Loaded from PRODIA_TOKEN env var
  baseURL?: string;  // Default: https://inference.prodia.com/v2
  headers?: Record<string, string>;
  fetch?: FetchFunction;
