export function createProdia(options: ProdiaProviderSettings = {}): ProdiaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix({
      Authorization: `Bearer ${loadApiKey({
        apiKey: options.apiKey,
        environmentVariableName: 'PRODIA_TOKEN',
        description: 'Prodia',
      })}`,
      ...options.headers,
    }, `ai-sdk/prodia/${VERSION}`);

  return {
    specificationVersion: 'v3',
    imageModel: (modelId) => new ProdiaImageModel(modelId, { ... }),
    languageModel: (modelId) => new ProdiaLanguageModel(modelId, { ... }),
    videoModel: (modelId) => new ProdiaVideoModel(modelId, { ... }),
    embeddingModel: (modelId) => { throw new NoSuchModelError(...); },
  };
}

export const prodia = createProdia();  // Default singleton export
```

**Image Model Implementation Pattern:**
```typescript
export class ProdiaImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;  // e.g., 'prodia.image'
  }

  constructor(
    readonly modelId: ProdiaImageModelId,
    private readonly config: ProdiaModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // 1. Parse provider-specific options
    const prodiaOptions = await parseProviderOptions({
      provider: 'prodia',
      providerOptions: options.providerOptions,
      schema: prodiaImageModelOptionsSchema,
    });

    // 2. Build request body
    const body = { type: this.modelId, config: jobConfig };

    // 3. Make API call
    const { value: multipartResult, responseHeaders } = await postToApi({
      url: `${this.config.baseURL}/job?price=true`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: { content: JSON.stringify(body), values: body },
      failedResponseHandler: prodiaFailedResponseHandler,
      successfulResponseHandler: createMultipartResponseHandler(),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // 4. Return structured response
    return {
      images: [imageBytes],
      warnings,
      providerMetadata: {
        prodia: {
          images: [buildProdiaProviderMetadata(jobResult)],
        },
      },
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}
```

