export function createProdia(options: ProdiaProviderSettings = {}): ProdiaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix({
      Authorization: `Bearer ${loadApiKey({
        apiKey: options.apiKey,
        environmentVariableName: 'PRODIA_TOKEN',
        description: 'Prodia',
      })}`,
      ...options.headers,
    }, `ai-sdk/prodia/${VERSION}`);

  return {
    specificationVersion: 'v3',
    imageModel: (modelId) => new ProdiaImageModel(modelId, { ... }),
    languageModel: (modelId) => new ProdiaLanguageModel(modelId, { ... }),
    videoModel: (modelId) => new ProdiaVideoModel(modelId, { ... }),
    embeddingModel: (modelId) => { throw new NoSuchModelError(...); },
  };
}

