1	import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
2	import type { InferSchema } from '@ai-sdk/provider-utils';
3	import {
4	  combineHeaders,
5	  lazySchema,
6	  parseJSON,
7	  parseProviderOptions,
8	  postToApi,
9	  resolve,
10	  zodSchema,
11	} from '@ai-sdk/provider-utils';
12	import { z } from 'zod/v4';
13	import type { ProdiaModelConfig } from './prodia-api';
14	import {
15	  buildProdiaProviderMetadata,
16	  parseMultipart,
17	  prodiaFailedResponseHandler,
18	  prodiaJobResultSchema,
19	} from './prodia-api';
20	import type { ProdiaJobResult } from './prodia-api';
21	import type { ProdiaImageModelId } from './prodia-image-settings';
22	
23	export class ProdiaImageModel implements ImageModelV3 {
24	  readonly specificationVersion = 'v3';
25	  readonly maxImagesPerCall = 1;
26	
27	  get provider(): string {
28	    return this.config.provider;
29	  }
30	
31	  constructor(
32	    readonly modelId: ProdiaImageModelId,
33	    private readonly config: ProdiaModelConfig,
34	  ) {}
35	
36	  private async getArgs({
37	    prompt,
38	    size,
39	    seed,
40	    providerOptions,
41	  }: Parameters<ImageModelV3['doGenerate']>[0]) {
42	    const warnings: Array<SharedV3Warning> = [];
43	
44	    const prodiaOptions = await parseProviderOptions({
45	      provider: 'prodia',
46	      providerOptions,
47	      schema: prodiaImageModelOptionsSchema,
48	    });
49	
50	    let width: number | undefined;
51	    let height: number | undefined;
52	    if (size) {
53	      const [widthStr, heightStr] = size.split('x');
54	      width = Number(widthStr);
55	      height = Number(heightStr);
56	      if (
57	        !widthStr ||
58	        !heightStr ||
59	        !Number.isFinite(width) ||
60	        !Number.isFinite(height)
61	      ) {
62	        warnings.push({
63	          type: 'unsupported',
64	          feature: 'size',
65	          details: `Invalid size format: ${size}. Expected format: WIDTHxHEIGHT (e.g., 1024x1024)`,
66	        });
67	        width = undefined;
68	        height = undefined;
69	      }
70	    }
71	
72	    const jobConfig: Record<string, unknown> = {
73	      prompt,
74	    };
75	
76	    if (prodiaOptions?.width !== undefined) {
77	      jobConfig.width = prodiaOptions.width;
78	    } else if (width !== undefined) {
79	      jobConfig.width = width;
80	    }
81	
82	    if (prodiaOptions?.height !== undefined) {
83	      jobConfig.height = prodiaOptions.height;
84	    } else if (height !== undefined) {
85	      jobConfig.height = height;
86	    }
87	
88	    if (seed !== undefined) {
89	      jobConfig.seed = seed;
90	    }
91	    if (prodiaOptions?.steps !== undefined) {
92	      jobConfig.steps = prodiaOptions.steps;
93	    }
94	    if (prodiaOptions?.stylePreset !== undefined) {
95	      jobConfig.style_preset = prodiaOptions.stylePreset;
96	    }
97	    if (prodiaOptions?.loras !== undefined && prodiaOptions.loras.length > 0) {
98	      jobConfig.loras = prodiaOptions.loras;
99	    }
100	    if (prodiaOptions?.progressive !== undefined) {
101	      jobConfig.progressive = prodiaOptions.progressive;
102	    }
103	
104	    const body = {
105	      type: this.modelId,
106	      config: jobConfig,
107	    };
108	
109	    return { body, warnings };
110	  }
111	
112	  async doGenerate(
113	    options: Parameters<ImageModelV3['doGenerate']>[0],
114	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
115	    const { body, warnings } = await this.getArgs(options);
116	
117	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
118	    const combinedHeaders = combineHeaders(
119	      await resolve(this.config.headers),
120	      options.headers,
121	    );
122	
123	    const { value: multipartResult, responseHeaders } = await postToApi({
124	      url: `${this.config.baseURL}/job?price=true`,
125	      headers: {
126	        ...combinedHeaders,
127	        Accept: 'multipart/form-data; image/png',
128	        'Content-Type': 'application/json',
129	      },
130	      body: {
131	        content: JSON.stringify(body),
132	        values: body,
133	      },
134	      failedResponseHandler: prodiaFailedResponseHandler,
135	      successfulResponseHandler: createMultipartResponseHandler(),
136	      abortSignal: options.abortSignal,
137	      fetch: this.config.fetch,
138	    });
139	
140	    const { jobResult, imageBytes } = multipartResult;
141	
142	    return {
143	      images: [imageBytes],
144	      warnings,
145	      providerMetadata: {
146	        prodia: {
147	          images: [buildProdiaProviderMetadata(jobResult)],
148	        },
149	      },
150	      response: {
151	        modelId: this.modelId,
152	        timestamp: currentDate,
153	        headers: responseHeaders,
154	      },
155	    };
156	  }
157	}
158	
159	const stylePresets = [
160	  '3d-model',
161	  'analog-film',
162	  'anime',
163	  'cinematic',
164	  'comic-book',
165	  'digital-art',
166	  'enhance',
167	  'fantasy-art',
168	  'isometric',
169	  'line-art',
170	  'low-poly',
171	  'neon-punk',
172	  'origami',
173	  'photographic',
174	  'pixel-art',
175	  'texture',
176	  'craft-clay',
177	] as const;
178	
179	export const prodiaImageModelOptionsSchema = lazySchema(() =>
180	  zodSchema(
181	    z.object({
182	      /**
183	       * Amount of computational iterations to run. More is typically higher quality.
184	       */
185	      steps: z.number().int().min(1).max(4).optional(),
186	      /**
187	       * Width of the output image in pixels.
188	       */
189	      width: z.number().int().min(256).max(1920).optional(),
190	      /**
191	       * Height of the output image in pixels.
192	       */
193	      height: z.number().int().min(256).max(1920).optional(),
194	      /**
195	       * Apply a visual theme to your output image.
196	       */
197	      stylePreset: z.enum(stylePresets).optional(),
198	      /**
199	       * Augment the output with a LoRa model.
200	       */
201	      loras: z.array(z.string()).max(3).optional(),
202	      /**
203	       * When using JPEG output, return a progressive JPEG.
204	       */
205	      progressive: z.boolean().optional(),
206	    }),
207	  ),
208	);
209	
210	export type ProdiaImageModelOptions = InferSchema<
211	  typeof prodiaImageModelOptionsSchema
212	>;
213	
214	interface MultipartResult {
215	  jobResult: ProdiaJobResult;
216	  imageBytes: Uint8Array;
217	}
218	
219	function createMultipartResponseHandler() {
220	  return async ({
221	    response,
222	  }: {
223	    response: Response;
224	  }): Promise<{
225	    value: MultipartResult;
226	    responseHeaders: Record<string, string>;
227	  }> => {
228	    const contentType = response.headers.get('content-type') ?? '';
229	    const responseHeaders: Record<string, string> = {};
230	    response.headers.forEach((value, key) => {
231	      responseHeaders[key] = value;
232	    });
233	
234	    const boundaryMatch = contentType.match(/boundary=([^\s;]+)/);
235	    if (!boundaryMatch) {
236	      throw new Error(
237	        `Prodia response missing multipart boundary in content-type: ${contentType}`,
238	      );
239	    }
240	    const boundary = boundaryMatch[1];
241	
242	    const arrayBuffer = await response.arrayBuffer();
243	    const bytes = new Uint8Array(arrayBuffer);
244	
245	    const parts = parseMultipart(bytes, boundary);
246	
247	    let jobResult: ProdiaJobResult | undefined;
248	    let imageBytes: Uint8Array | undefined;
249	
250	    for (const part of parts) {
251	      const contentDisposition = part.headers['content-disposition'] ?? '';
252	      const partContentType = part.headers['content-type'] ?? '';
253	
254	      if (contentDisposition.includes('name="job"')) {
255	        const jsonStr = new TextDecoder().decode(part.body);
256	        jobResult = await parseJSON({
257	          text: jsonStr,
258	          schema: zodSchema(prodiaJobResultSchema),
259	        });
260	      } else if (contentDisposition.includes('name="output"')) {
261	        imageBytes = part.body;
262	      } else if (partContentType.startsWith('image/')) {
263	        imageBytes = part.body;
264	      }
265	    }
266	
267	    if (!jobResult) {
268	      throw new Error('Prodia multipart response missing job part');
269	    }
270	    if (!imageBytes) {
271	      throw new Error('Prodia multipart response missing output image');
272	    }
273	
274	    return {
275	      value: { jobResult, imageBytes },
276	      responseHeaders,
277	    };
278	  };
279	}
