100	function loadDeprecatedApiKey(): string | undefined {
101	  if (typeof process === 'undefined') {
102	    return undefined;
103	  }
104	  // If the new env var is set, let loadApiKey handle it
105	  if (typeof process.env.TOGETHER_API_KEY === 'string') {
106	    return undefined;
107	  }
108	  const key = process.env.TOGETHER_AI_API_KEY;
109	  if (typeof key === 'string') {
110	    console.warn(
111	      'TOGETHER_AI_API_KEY is deprecated and will be removed in a future release. Please use TOGETHER_API_KEY instead.',
112	    );
113	  }
114	  return key;
115	}
