22	    'Content-Type: image/png\r\n',
23	    '\r\n',
24	  ];
25	
26	  const headerPart = Buffer.from(parts.join(''));
27	  const endPart = Buffer.from(`\r\n--${boundary}--\r\n`);
28	
29	  const body = Buffer.concat([headerPart, imageBuffer, endPart]);
30	
31	  return {
32	    body,
33	    contentType: `multipart/form-data; boundary=${boundary}`,
