```typescript
export function createProdia(options: ProdiaProviderSettings = {}): ProdiaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () => withUserAgentSuffix({
    Authorization: `Bearer ${loadApiKey({ apiKey: options.apiKey, environmentVariableName: 'PRODIA_TOKEN', description: 'Prodia' })}`,
    ...options.headers,
  }, `ai-sdk/prodia/${VERSION}`);

  const createImageModel = (modelId) => new ProdiaImageModel(modelId, {
    provider: 'prodia.image', baseURL, headers: getHeaders, fetch: options.fetch,
  });

  return {
    specificationVersion: 'v3',
    languageModel: (modelId) => { throw new NoSuchModelError({ modelId, modelType: 'languageModel' }); },
    imageModel: createImageModel,
    image: createImageModel,
    embeddingModel: (modelId) => { throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' }); },
  };
}
