export class TogetherAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;
  get provider(): string { return this.config.provider; }
  constructor(readonly modelId, private config) {}

  async doGenerate(options): Promise<...> {
    const warnings = [];
    const togetheraiOptions = await parseProviderOptions({ provider: 'togetherai', providerOptions, schema });

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: { model: this.modelId, prompt, seed, n, response_format: 'base64', ...togetheraiOptions },
      failedResponseHandler: createJsonErrorResponseHandler({ errorSchema, errorToMessage }),
      successfulResponseHandler: createJsonResponseHandler(responseSchema),
      abortSignal, fetch: this.config.fetch,
    });

    return { images: response.data.map(item => item.b64_json), warnings, response: { timestamp, modelId, headers } };
  }
}
